```class Solution {
public:
    string reverseWords(string s) {
        string result;
        string word;
        for (int i = 0; i < s.length(); i++) {
            if (s[i] == ' ') {
                result += word + ' ';
                word = "";
            } else {
                word += s[i];
            }
        }
        result += word;
        for (int i = 0; i < result.length(); i++) {
            if (result[i] != ' ') {
                result[i] = result[result.length() - i - 1];
            }
        }
        return result;
    }
};```
